// Verify directions API returns hourly scoring arrays for compass rose animation
async function testDirectionsHourlyStructure() {
  const BASE = 'http://localhost:3001';

  // Fetch directions for Marseille — known coastal location
  const res = await fetch(`${BASE}/api/directions?lat=43.3&lon=5.37`);
  assertEquals(res.status, 200, 'Should return 200');

  const body = await res.json();

  // Verify top-level structure
  assert(body.origin !== undefined, 'Should have origin');
  assert(Array.isArray(body.directions), 'Should have directions array');
  assertEquals(body.directions.length, 8, 'Should have 8 compass directions');

  // Verify each direction has the hourly array
  for (const dir of body.directions) {
    assert(dir.name, 'Direction should have a name');
    assert(typeof dir.score === 'number', `${dir.name}: score should be a number`);
    assert(typeof dir.rating === 'string', `${dir.name}: rating should be a string`);
    assert(typeof dir.summary === 'string', `${dir.name}: summary should be a string`);

    // Hourly array must exist and have entries
    assert(Array.isArray(dir.hourly), `${dir.name}: should have hourly array`);
    assert(dir.hourly.length > 0, `${dir.name}: hourly array should not be empty`);

    // Verify structure of first and last hourly entries
    for (const idx of [0, dir.hourly.length - 1]) {
      const h = dir.hourly[idx];
      assert(typeof h.score === 'number', `${dir.name} hourly[${idx}]: score should be a number`);
      assert(h.score >= 0 && h.score <= 100, `${dir.name} hourly[${idx}]: score should be 0-100`);
      assert(typeof h.rating === 'string', `${dir.name} hourly[${idx}]: rating should be a string`);
      assert(['green', 'yellow', 'red'].includes(h.rating), `${dir.name} hourly[${idx}]: rating should be green/yellow/red`);
      assert(typeof h.summary === 'string', `${dir.name} hourly[${idx}]: summary should be a string`);
      assert(h.summary.length > 0, `${dir.name} hourly[${idx}]: summary should not be empty`);
    }
  }

  // Verify all directions have the same hourly length (same forecast period)
  const lengths = body.directions.map((d) => d.hourly.length);
  const uniqueLengths = [...new Set(lengths)];
  assertEquals(uniqueLengths.length, 1, 'All directions should have same hourly array length');
}

